def binary_search(arr, low, high, x):
    """
    Belirtilen aralıkta ikili arama yapar.
    """
    while low <= high:
        mid = low + (high - low) // 2
        if arr[mid] == x:
            return mid
        elif arr[mid] < x:
            low = mid + 1
        else:
            high = mid - 1
    return -1

def exponential_search(arr, x):
    """
    Üstel Arama algoritması ile bir elemanı dizide arar.
    Önce arama yapılacak olası aralığı bulur, ardından bu aralıkta ikili arama yapar.
    """
    n = len(arr)

    if n == 0:
        return -1 # Boş dizi

    # Eleman dizinin ilk konumundaysa
    if arr[0] == x:
        return 0

    # İkili arama için aralığı bulmak için 'i'yi sürekli ikiye katla
    i = 1
    while i < n and arr[i] <= x:
        i = i * 2

    # Bulunan aralıkta ikili arama çağrısı yap (i/2'den min(i, n-1)'e kadar)
    return binary_search(arr, i // 2, min(i, n - 1), x)
